# app.py
from flask import Flask, render_template, abort, request

app = Flask(__name__)

@app.route('/')
def index():
    if request.args.get('raise_value_error'):
        raise ValueError("Bu bir değer hatasıdır.")
    if request.args.get('raise_404'):
        abort(404)
    if request.args.get('raise_500'):
        raise Exception("Bu bir beklenmedik sunucu hatasıdır.")
    return "Ana sayfa. Hata tetiklemek için URL'ye '?raise_value_error=True', '?raise_404=True' veya '?raise_500=True' ekleyin."

@app.errorhandler(404)
def page_not_found(error):
    return render_template('error.html', error_code=404, error_message="Sayfa Bulunamadı"), 404

@app.errorhandler(500)
def internal_server_error(error):
    return render_template('error.html', error_code=500, error_message="İç Sunucu Hatası"), 500

@app.errorhandler(ValueError)
def handle_value_error(error):
    return render_template('error.html', error_code="ValueError", error_message=str(error)), 400

@app.errorhandler(Exception)
def handle_exception(error):
    return render_template('error.html', error_code=500, error_message=f"Beklenmedik Bir Hata Oluştu: {str(error)}"), 500

if __name__ == '__main__':
    app.run(debug=True)
